{
    "level": "A1–A2",
    "intro": "]W tym temacie dowiesz się <strong>przedimka zerowego</strong> - kiedy w języku angielskim <strong>artykuł nie jest potrzebny</strong> wcześniej rzeczownik.",
    "rules": [
        {
            "label": "Streszczenia",
            "color": "emerald",
            "text": "<strong>Pojęcia abstrakcyjne</strong> – znaczenie ogólne:",
            "example": "Miłość jest ważna. / Lubię muzykę."
        },
        {
            "label": "liczba mnoga",
            "color": "blue",
            "text": "<strong>liczba mnoga ogólnie</strong> – wszyscy przedstawiciele:",
            "example": "Psy są lojalne. Lubię koty. Co to jest przedimek zerowy?"
        },
        {
            "label": "Імена",
            "color": "amber",
            "text": "<strong>Власні назви</strong> — країни, міста, імена:",
            "example": "Ukraine, London, John"
        }
    ]
}

{
    "title": "1. Що таке нульовий артикль?",
    "intro": "Przedimek zerowy to brak przedimka przed rzeczownikiem:",
    "items": [
        {
            "label": "Ř Artykuł",
            "title": "Brak przedimka",
            "subtitle": "Rzeczownik bez przedimka lub ma wartość zero artykuł"
        },
        {
            "label": "Często",
            "title": "Bardzo często",
            "subtitle": "W języku angielskim istnieje wiele przypadków, gdy artykuł nie jest potrzebny"
        },
        {
            "label": "Zasady",
            "title": "Istnieją zasady",
            "subtitle": "Pewne kategorie słów zawsze nie zawiera przedimka"
        }
    ]
}

{
    "title": "2. Rzeczowniki abstrakcyjne i niepoliczalne",
    "sections": [
        {
            "label": "Pojęcia abstrakcyjne",
            "color": "emerald",
            "description": "<strong>Rzeczowniki abstrakcyjne</strong> w sensie ogólnym – bez przedimka.",
            "examples": [
                {
                    "en": "Miłość jest ważna.",
                    "ua": "Miłość jest ważna."
                },
                {
                    "en": "Szczęście czyni życie lepszym.",
                    "ua": " lepiej."
                },
                {
                    "en": "Wiedza to potęga.",
                    "ua": "Wiedza to potęga."
                },
                {
                    "en": "Wolność jest cenna.",
                    "ua": "Wolność jest cenna."
                }
            ]
        },
        {
            "label": "Niepoliczalne w ogólne",
            "color": "sky",
            "description": "<strong>Rzeczowniki niepoliczalne</strong> ogólnie – bez rodzajnika.",
            "examples": [
                {
                    "en": "Kocham muzykę.",
                    "ua": "Kocham muzykę. (muzyka ogólnie)"
                },
                {
                    "en": "Woda jest niezbędna.",
                    "ua": "Woda jest niezbędna. (ogólnie woda)"
                },
                {
                    "en": "Pieniądze szczęścia nie dają.",
                    "ua": "Pieniądze szczęścia nie dają."
                },
                {
                    "en": "Informacja jest wszędzie.",
                    "ua": "Informacja jest wszędzie."
                }
            ]
        },
        {
            "label": "Uwaga!",
            "color": "amber",
            "description": "Jeśli chodzi o <strong>konkretną</strong> część, wymagany jest artykuł <strong>the</strong>.",
            "examples": [
                {
                    "en": "Kocham muzykę. (ogólnie)",
                    "ua": "Uwielbiam muzykę."
                },
                {
                    "en": "Uwielbiam muzykę w tym filmie. (konkretny)",
                    "ua": "Podoba mi się muzyka z tego filmu."
                }
            ],
            "note": "📌 Ogólna koncepcja to Ø, konkretna koncepcja to."
        }
    ]
}

{
    "title": "3. Liczba mnoga w sensie ogólnym",
    "sections": [
        {
            "label": "Stwierdzenia ogólne",
            "color": "blue",
            "description": "Kiedy mówimy o <strong>wszystkich członkach grupy</strong> – bez przedimka.",
            "examples": [
                {
                    "en": "Psy to zwierzęta lojalne.",
                    "ua": "Psy to zwierzęta lojalne. (wszystkie psy)"
                },
                {
                    "en": "Koty lubią spać.",
                    "ua": "Koty lubią spać. (ogólnie o kotach)"
                },
                {
                    "en": "Książki są drogie.",
                    "ua": "Książki są drogie. (ogólnie książki)"
                },
                {
                    "en": "Dzieci potrzebują miłości.",
                    "ua": "Dzieci potrzebują miłości."
                }
            ]
        },
        {
            "label": "Ulubienia i hobby",
            "color": "emerald",
            "description": "Z czasownikami <strong>lubić, kochać, nienawidzić</strong> o sprawach ogólnych – bez przedimka.",
            "examples": [
                {
                    "en": "I jak jabłka.",
                    "ua": "Uwielbiam jabłka (ogólnie jabłka)"
                },
                {
                    "en": "Ona kocha kwiaty.",
                    "ua": "Uwielbia kwiaty."
                },
                {
                    "en": "Nienawidzi pająków.",
                    "ua": "Nienawidzi pająki."
                },
                {
                    "en": "Lubimy filmy.",
                    "ua": " filmy."
                }
            ]
        },
        {
            "label": "Zawody mnogie",
            "color": "sky",
            "description": "Ogólnie rzecz biorąc, liczba mnoga zawodów nie zawiera przedimka.",
            "examples": [
                {
                    "en": "Nauczyciele pracują ciężko.",
                    "ua": "Nauczyciele ciężko pracują."
                },
                {
                    "en": "Lekarze ratują życie.",
                    "ua": "Lekarze ratują życie."
                },
                {
                    "en": "Inżynierowie rozwiązują problemy.",
                    "ua": "Inżynierowie rozwiązują problemy."
                }
            ]
        }
    ]
}

{
    "title": "4. Imiona własne (imiona, kraje, miasta)",
    "sections": [
        {
            "label": "Imiona osób",
            "color": "purple",
            "description": "<strong>Imiona i nazwiska</strong> - bez przedimka.",
            "examples": [
                {
                    "en": "John jest moim przyjacielem.",
                    "ua": "John jest moim przyjacielem przyjaciel."
                },
                {
                    "en": "Maria tu pracuje.",
                    "ua": "Maria tu pracuje."
                },
                {
                    "en": "Mr. Smith zadzwonił wczoraj.",
                    "ua": "Pan. Smith zadzwonił wczoraj."
                },
                {
                    "en": "Prezydent Zełenski przemawiał dzisiaj.",
                    "ua": "Prezydent Zełenski przemawiał dzisiaj."
                }
            ]
        },
        {
            "label": "Kraje i miasta",
            "color": "emerald",
            "description": "<strong>Większość krajów i miast</strong> — brak artykułu.",
            "examples": [
                {
                    "en": "Ukraina jest piękna.",
                    "ua": "Ukraina jest piękna."
                },
                {
                    "en": "Mieszkam w Kijowie.",
                    "ua": "Mieszkam Kijów."
                },
                {
                    "en": "Francja jest w Europie.",
                    "ua": "Francja w Europie."
                },
                {
                    "en": "Londyn to duże miasto.",
                    "ua": "Londyn to duże miasto."
                }
            ]
        },
        {
            "label": "Wyjątki od artykułu THE",
            "color": "rose",
            "description": "Niektóre kraje <strong>zawsze z</strong> (liczba mnoga lub związek):",
            "examples": [
                {
                    "en": "USA, Stany Zjednoczone",
                    "ua": "USA, Stany Zjednoczone"
                },
                {
                    "en": "Wielka Brytania, Wielka Brytania",
                    "ua": "Wielka Brytania, Stany Zjednoczone Królestwo"
                },
                {
                    "en": "Holandia",
                    "ua": "Holandia"
                },
                {
                    "en": "Filipiny",
                    "ua": "Filipiny"
                }
            ],
            "note": "⚠️ Należy pamiętać o tych wyjątkach!"
        }
    ]
}

{
    "title": "5. Obiekty geograficzne bez przedimka",
    "sections": [
        {
            "label": "Kontynenty",
            "color": "sky",
            "description": "<strong>Nazwy kontynentów</strong> — bez przedimka.",
            "examples": [
                {
                    "en": "Europa, Azja, Afryka",
                    "ua": "Europa, Azja, Afryka"
                },
                {
                    "en": "Ameryka Północna, Ameryka Południowa",
                    "ua": "Ameryka Północna, Ameryka Południowa"
                },
                {
                    "en": "Australia to kontynent.",
                    "ua": "Australia to kontynent."
                }
            ]
        },
        {
            "label": "Góry (indywidualne szczyty)",
            "color": "emerald",
            "description": "<strong>Pojedyncze góry</strong> – brak artykułu (ale systemy górskie – z).",
            "examples": [
                {
                    "en": "Mount Everest",
                    "ua": "Mount Everest"
                },
                {
                    "en": "Hoverla to najwyższy szczyt w Ukraina.",
                    "ua": "Hoverla to najwyższy szczyt Ukrainy."
                },
                {
                    "en": "ALE: Alpy, Karpaty",
                    "ua": "ALE: Alpy, Karpaty (systemy — z)"
                }
            ]
        },
        {
            "label": "Jeziora (z jeziorem)",
            "color": "blue",
            "description": "Jeśli <strong>Jezioro + nazwa</strong> — nie artykuł.",
            "examples": [
                {
                    "en": "Jezioro Bajkał",
                    "ua": "Jezioro Bajkał"
                },
                {
                    "en": "Jezioro Superior",
                    "ua": "Osero Superior"
                },
                {
                    "en": "ALE: Bajkał (bez słowa Jezioro)",
                    "ua": "ALE: bez słowa Jezioro potrzebne jest "
                }
            ]
        }
    ]
}

{
    "title": "6. Wyrażenia regularne bez przedimka",
    "sections": [
        {
            "label": "Miejsca (w/do + miejsce)",
            "color": "amber",
            "description": "W wyrażeniach regularnych z <strong>miejscami</strong> — bez przedimka.",
            "examples": [
                {
                    "en": "w domu, w pracy, w szkole",
                    "ua": "w domu, w pracy, w szkoła"
                },
                {
                    "en": "idź do łóżka, idź do pracy, idź do kościoła",
                    "ua": "pójdź do łóżka, idź do pracy, idź do kościoła"
                },
                {
                    "en": "w szpitalu (Wielka Brytania), w więzieniu",
                    "ua": "na uniwersytecie, w college’u"
                },
                {
                    "en": "at university, at college",
                    "ua": "na uniwersytecie, w uczelnie"
                }
            ]
        },
        {
            "label": "Transport (autobusem, transportem)",
            "color": "sky",
            "description": "Z przyimkiem <strong>by</strong> — bez przedimka.",
            "examples": [
                {
                    "en": "samochodem, autobusem, pociągiem",
                    "ua": "samochodem, autobusem, pociągiem"
                },
                {
                    "en": "samolotem, łodzią, rowerem",
                    "ua": "samolotem, łodzią, rowerem"
                },
                {
                    "en": "ALE: w autobusie, w samochodzie",
                    "ua": "ALE: z włączeniem/wejściem wymaga artykułu"
                }
            ]
        },
        {
            "label": "Jedzenie (posiłki)",
            "color": "emerald",
            "description": "Nazwy <strong>posiłki</strong> — bez artykułu.",
            "examples": [
                {
                    "en": "zjedz śniadanie, zjedz lunch, zjedz kolację",
                    "ua": "śniadanie, zjedz lunch, zjedz kolację"
                },
                {
                    "en": "Co na obiad?",
                    "ua": "Co na obiad?"
                },
                {
                    "en": "po śniadaniu",
                    "ua": "po śniadaniu"
                },
                {
                    "en": "ALE: obiad był pyszny",
                    "ua": "ALE: konkretny obiad jest z"
                }
            ]
        }
    ]
}

{
    "title": "7. Sport, języki, przedmioty",
    "sections": [
        {
            "label": "Sport",
            "color": "purple",
            "description": "<strong>Nazwy gier sportowych</strong> — brak artykułu.",
            "examples": [
                {
                    "en": "grać w piłkę nożną, grać w tenisa",
                    "ua": "grać w piłkę nożną, grać w tenisa"
                },
                {
                    "en": "Lubię koszykówka.",
                    "ua": "Lubię koszykówkę."
                },
                {
                    "en": "Gra w siatkówkę.",
                    "ua": "Gra w siatkówkę."
                }
            ]
        },
        {
            "label": "Języki",
            "color": "blue",
            "description": "<strong>Nazwy języków</strong> – bez artykuł.",
            "examples": [
                {
                    "en": "Mówię po angielsku.",
                    "ua": "Mówię po angielsku."
                },
                {
                    "en": "Uczy się ukraińskiego.",
                    "ua": "Uczy się ukraińskiego."
                },
                {
                    "en": "Francuski jest piękny.",
                    "ua": "Francuski jest piękny."
                },
                {
                    "en": "ALE: język angielski",
                    "ua": "ALE: za pomocą słowa język"
                }
            ]
        },
        {
            "label": "przedmioty edukacyjne",
            "color": "emerald",
            "description": "<strong>przedmioty szkolne</strong> — brak artykułu.",
            "examples": [
                {
                    "en": "Lubię to matematyka.",
                    "ua": "Lubię matematykę."
                },
                {
                    "en": "Historia jest interesująca.",
                    "ua": "Historia jest interesująca."
                },
                {
                    "en": "Uczy się biologii.",
                    "ua": "Uczy się biologii."
                }
            ]
        }
    ]
}

{
    "title": "8. Pora dnia i święta",
    "sections": [
        {
            "label": "Dni tygodnia, miesiące, święta",
            "color": "rose",
            "description": "<strong>Dni, miesiące i święta</strong> — brak artykułu.",
            "examples": [
                {
                    "en": "Poniedziałek, wtorek, środa",
                    "ua": "Poniedziałek, wtorek, środa"
                },
                {
                    "en": "styczeń, luty, marzec",
                    "ua": "styczeń, luty, marzec"
                },
                {
                    "en": "Boże Narodzenie, Wielkanoc, Nowy Rok",
                    "ua": "Boże Narodzenie, Wielkanoc, Nowy Rok"
                },
                {
                    "en": "w poniedziałek, w styczniu",
                    "ua": " Styczeń"
                }
            ]
        },
        {
            "label": "Pory roku",
            "color": "amber",
            "description": "<strong>Pory roku</strong> – zazwyczaj bez przedimka (ale mogą być odmiany).",
            "examples": [
                {
                    "en": "Wiosna jest piękna.",
                    "ua": "Wiosna jest piękna."
                },
                {
                    "en": "Lubię to lato.",
                    "ua": "Uwielbiam lato."
                },
                {
                    "en": "jesień, zimę",
                    "ua": "jesień, zimę"
                },
                {
                    "en": "ALE: lato 2023",
                    "ua": "ALE: konkretne lato może pochodzić z "
                }
            ]
        },
        {
            "label": "Części dnia (ogólnie)",
            "color": "sky",
            "description": "W niektórych wyrażeniach — bez przedimka.",
            "examples": [
                {
                    "en": "w nocy (bez!)[[[CODX_19]]]w nocy (bez!)",
                    "ua": "вночі (без the!)"
                },
                {
                    "en": "w dzień, przez noc",
                    "ua": "w dzień, w nocy"
                },
                {
                    "en": "ALE: rano, po południu",
                    "ua": "w)[[CODX_SEG_24]]]9. Tabela porównawcza: Ø vs "
                }
            ]
        }
    ]
}

{
    "title": "9. Порівняльна таблиця: Ø vs The",
    "intro": "Główne przypadki, gdy artykuł NIE jest potrzebny:",
    "rows": [
        {
            "en": "Ogólne / abstrakcyjne",
            "ua": "Ogólne / abstrakcyjne",
            "note": "Ř: Miłość jest ważna. / Muzyka jest świetna."
        },
        {
            "en": "Ogólnie liczba mnoga",
            "ua": "Ogólnie liczba mnoga",
            "note": "Ř: Psy są lojalne. Książki są drogie. Smith"
        },
        {
            "en": "Countries, cities",
            "ua": "Країни, міста",
            "note": "Ø: Ukraine, London (but: the USA, the UK)"
        },
        {
            "en": "Names",
            "ua": "Імена",
            "note": "Ø: John, Maria, Mr. Smith"
        },
        {
            "en": "Naprawiono wyrażenia",
            "ua": "Wyrażenia regularne",
            "note": "Ř: w domu, w samochodzie, zjedz śniadanie"
        },
        {
            "en": "Sport, języki",
            "ua": "Sport, języki",
            "note": "Ř: graj w piłkę nożną, mów Polish"
        }
    ],
    "warning": "📌 Jeśli coś jest <strong>konkretne</strong> lub <strong>oznaczone</strong> — używamy <strong>the</strong>!"
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Artykuł przed abstrakcjami.",
            "wrong": "Miłość jest ważna.",
            "right": "​​​​ <span class="font-mono">Miłość jest ważne.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Artykuł przed moim pobytem na Ukrainie. lojalny.",
