{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Czy potrzebujesz przedimka?",
    "select_intro": "Określ, czy w tych zdaniach potrzebny jest przedimek.",
    "selects": [
        {
            "label": "___ miłość jest ważna. (Ř / the)",
            "prompt": "Potrzebujesz artykułu?"
        },
        {
            "label": "Mieszkam w ___ Ukrainie. (Ř / the)",
            "prompt": "Potrzebujesz artykułu?"
        },
        {
            "label": "___ psy są lojalne. (Ř / the)",
            "prompt": "Potrzebujesz artykułu?"
        },
        {
            "label": "Mówię ___ po angielsku. (Ř/the) __ autobus. błąd w artykule.",
            "prompt": "Потрібен артикль?"
        }
    ],
    "options": [
        "Ø (без артикля)",
        "the"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши Ø (без артикля) або the.",
    "inputs": [
        {
            "before": "I go to ___ work by ___ bus.",
            "after": "→"
        },
        {
            "before": "___ freedom is important.",
            "after": "→"
        },
        {
            "before": "She lives in ___ USA.",
            "after": "→"
        }
    ],
    "rephrase_title": "Вправа 3. Виправ помилки",
    "rephrase_intro": "Знайди і виправ помилку з артиклем.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Miłość jest piękna.",
            "example_target": "Miłość jest piękna."
        },
        {
            "original": "1. Mieszkam na Ukrainie.",
